var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" 커튼콜 작전 이후로 오랜만이군요.","JPN":" カーテンコール作戦以来、久しぶりですね。","ENG":"I believe we last spoke during Operation Curtain Call.","TWN":"謝幕作戰行動之後，好久不見了。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" 카르데나스 전대장님.","JPN":" カルデナス戦隊長。","ENG":"Cardenas Commander.","TWN":"卡特納斯戰隊長。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SID_CARDENAS_NPC_NULL","text":{"KOREA":" 그로부터 벌써 3년이나 지나다니. 시간이 참 빠르군.","JPN":" あれからもう3年か。時間とは早いものだ。","ENG":"I can't believe it's already been three years. Time really does fly.","TWN":"已經過去3年了，時間真是快啊。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SID_CARDENAS_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L6_1","type":"subtitle","speaker":null,"text":{"KOREA":" 관리국 제10 유격전대 <color=#ffd34c>카르데나스</color>\\n전대장 시드","JPN":" 管理局第10遊撃戦隊<color=#ffd34c>カルデナス</color>\\n戦隊長シド","ENG":"Administration 10th Guerrilla Division <color=#ffd34c>Cardenas</color>\\nCommander Sid","TWN":"管理局第10遊擊戰隊<color=#ffd34c>卡特納斯</color>\\n戰隊長錫德"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SID_CARDENAS_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SID_CARDENAS_NPC_NULL","text":{"KOREA":" 그동안 잘 지냈나, 스위프트 부전대장.","JPN":" 元気だったか、スウィフト副戦隊長。","ENG":"How have you been, Deputy Commander Swift?","TWN":"你最近怎麼樣，斯威福特副戰隊長？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SID_CARDENAS_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" 그때는 지원을 보내주셔서 감사했습니다.","JPN":" あの時はご支援、ありがとうございました。","ENG":"I first want to thank you for sending reinforcements that day, sir.","TWN":"我很感激大家那時候的支持。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" 하지만 갑자기 무슨 일이시죠? 프라이빗 채널로 연락하시다니.","JPN":" でも、いきなりどうしたんです？　プライベートチャンネルから連絡をくださるなんて。","ENG":"What do I owe this pleasure of your calling me on a private line?","TWN":"但突然發生什麼事了，你怎麼會突然私下聯繫我？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SID_CARDENAS_NPC_NULL","text":{"KOREA":" 걱정말게. 자네에게 손해가 될 만한 이야기는 아닐 테니까.","JPN":" 心配するな。君にとって悪い話ではないはずだ。","ENG":"Don't worry. What I'm about to discuss won't be a waste of your time.","TWN":"不用擔心。相信不會浪費你的時間的。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SID_CARDENAS_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SID_CARDENAS_NPC_NULL","text":{"KOREA":" 소문에 따르면, 자네 줄곧 엘리시움의 그림자를 쫓고 있다고 들었는데, 사실인가?","JPN":" 噂によると、君はずっとエリシウムのシャドウを追っていると聞いたのだが。本当か？","ENG":"I heard rumors that you're chasing after an Elysium Shadow. Is that true?","TWN":"我聽說你一直在尋找樂團的暗影，這是真的嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SID_CARDENAS_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" …….","JPN":" ……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" 나름 숨긴다고 숨겨왔는데 토끼보다 귀가 더 밝으시네요.","JPN":" ちゃんと隠してきたつもりですが、ウサギより素晴らしい聴力ですね。","ENG":"I tried my best to keep it discreet, but I guess you have better ears than that of a rabbit.","TWN":"我以為我瞞的很好，你的耳朵比兔子還靈呢。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SID_CARDENAS_NPC_NULL","text":{"KOREA":" 글쎄? 굳이 숨길 필요가 있나?","JPN":" ほう？　隠す必要があるのか？","ENG":"Really? But what was all the secrecy for?","TWN":"這個？有必要隱藏嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SID_CARDENAS_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SID_CARDENAS_NPC_NULL","text":{"KOREA":" 엘리시움 필하모닉에게 칼을 갈고 있는 자들은 자네뿐만이 아니야.","JPN":" エリシウムフィルハーモニーを狙っているのは君だけではない。","ENG":"You're not the only one who wants Elysium Philharmonic to be extinct.","TWN":"你們並不是唯一一個希望愛樂組織徹底消失的人。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SID_CARDENAS_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" …….","JPN":" ……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SID_CARDENAS_NPC_NULL","text":{"KOREA":" 피차 바쁜 몸이니, 본론만 전하지.","JPN":" お互い忙しい身だ。本題だけ伝えよう。","ENG":"We're both busy people, so I'll just cut to the chase.","TWN":"大家都很忙，我直接進入正題吧。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SID_CARDENAS_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SID_CARDENAS_NPC_NULL","text":{"KOREA":" 최근 엘리시움 필하모닉의 동태가 심상치 않아.","JPN":" 最近エリシウムフィルハーモニーの様子が怪しい。","ENG":"Recently, there have been unusual movements by the Elysium Philharmonic.","TWN":"愛樂組織最近動作異常。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SID_CARDENAS_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SID_CARDENAS_NPC_NULL","text":{"KOREA":" 첩보에 따르면, 활동을 중단했던 최고 단원들이 슬금슬금 모습을 드러내고 있어.","JPN":" 諜報によると、活動を中断していた首席奏者たちがこっそりと姿を現している。","ENG":"According to intel, the suspended Elite Members have started to show up.","TWN":"情報顯示，暫停活動的樂手正在秘密露面。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SID_CARDENAS_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SID_CARDENAS_NPC_NULL","text":{"KOREA":" 그 중에는 자네가 쫓고 있는 <color=#ffd34c>카르멘</color>도 관측되었지.","JPN":" その中には、君が追っている<color=#ffd34c>カルメン</color>も含まれる。","ENG":"Among them, <color=#ffd34c>Carmen</color>, the one you're after, was also seen.","TWN":"據觀測，其中就有你在追蹤的<color=#ffd34c>卡門</color>。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SID_CARDENAS_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" 카르멘……!","JPN":" カルメン……！","ENG":"Carmen...!","TWN":"卡門……！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SID_CARDENAS_NPC_NULL","text":{"KOREA":" 관리국은 지금 클리포트 게임을 앞두고 있어.","JPN":" 管理局は今、クリフォトゲームを目の前にしている。","ENG":"The Administration is currently preparing for the Qliphoth Game.","TWN":"管理局現在正在準備逆卡巴拉遊戲。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SID_CARDENAS_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SID_CARDENAS_NPC_NULL","text":{"KOREA":" 이런 상황에서 녀석들을 방치해두면, 틀림없이 중요한 순간에 발목을 잡히게 될 거야.","JPN":" このような状況でやつらを放置すると、きっと大事な瞬間に足元をすくわれるだろう。","ENG":"So if we leave them unattended in this situation, I have no doubt that they'll become our ball and chain at the most crucial moment.","TWN":"這種情況如果放任他們不管，到了關鍵時刻，他們肯定會出來搗亂的。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SID_CARDENAS_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SID_CARDENAS_NPC_NULL","text":{"KOREA":" 그래서 우리는 커튼콜의 공로자인 야크샤 전대에게 연합을 요청하고 싶네.","JPN":" それで私たちは、カーテンコールの功労者であるヤクシャー戦隊に連合を要請したい。","ENG":"That's why I'm requesting a coalition with the Yaksha Division, a contributor to Operation Curtain Call.","TWN":"所以，我想與夜叉戰隊結盟。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SID_CARDENAS_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" …….","JPN":" ……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" 관리국의 전력이라면, 단원들을 제거하는 건 그다지 문제가 되지 않을 겁니다.","JPN":" 管理局の戦力なら、奏者たちを排除するのは簡単でしょう。","ENG":"With the force of the Administration, eliminating the Elysium members won't be a problem.","TWN":"有了管理局的力量，消滅樂手也不是什麼大問題。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SID_CARDENAS_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" 하지만 마에스트로는 이야기가 다릅니다.","JPN":" ですが、マエストロは違います。","ENG":"But Maestra is different.","TWN":"但指揮家不好說。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SID_CARDENAS_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" 지난 작전에서 다른 전대들이 도와주지 않았다면, 전 이미 죽은 목숨이겠죠.","JPN":" 以前の作戦で他の戦隊の助けがなければ、私はすでに死んでいたでしょう。","ENG":"If the other divisions hadn't helped in the last operation, I'd be six feet under right now.","TWN":"上次作戰如果不是其他戰隊幫忙，我早就死了。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SID_CARDENAS_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SID_CARDENAS_NPC_NULL","text":{"KOREA":" 물론, 마에스트로가 가장 큰 문제이긴 하지.","JPN":" もちろん、一番の課題はマエストロだ。","ENG":"Of course, Maestra is our biggest threat.","TWN":"當然，指揮家是最大的問題。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SID_CARDENAS_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SID_CARDENAS_NPC_NULL","text":{"KOREA":" 하지만 괜찮아. 우리가 진짜 노리는 건, 필하모닉 홀이라는 이면세계 그 자체니까.","JPN":" だが、大丈夫。私たちの本当の狙いは、フィルハーモニーホールという裏世界そのものだからな。","ENG":"But she won't be an issue. Because what we're really after is the Counterside called Philharmonic Hall itself.","TWN":"不過沒關係。我們真正的目標是管弦樂廳所在的異界本身。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SID_CARDENAS_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" 이면세계 그 자체라고요?","JPN":" 裏世界そのものですって？","ENG":"Counterside itself?","TWN":"異界本身？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SID_CARDENAS_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" 그럼, 설마 침식 코어를 노리겠다는 건가요?","JPN":" では、まさか侵食コアを狙うということですか？","ENG":"Then, are you saying you're going after the Corruption Core?","TWN":"那麼，你瞄準的是那裡的侵蝕核心？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SID_CARDENAS_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SID_CARDENAS_NPC_NULL","text":{"KOREA":" 그래. 이면세계는 저마다 침식오염을 발생시키는 세계의 핵. 침식 코어가 존재하지.","JPN":" ああ。裏世界はそれぞれ侵食汚染を発生させる世界の核。侵食コアが存在する。","ENG":"Correct. Every Counterside has a core of the world that causes Corruption called the Corruption Core.","TWN":"沒錯。每個異界都存在引發侵蝕污染的世界核心……侵蝕核心。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SID_CARDENAS_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SID_CARDENAS_NPC_NULL","text":{"KOREA":" 우리가 엘리시움을 상대하는 사이, 내 동생이 이끄는 유격대가 침식 코어를 파괴할 거야.","JPN":" 私たちがエリシウムの相手をしている間に、私の妹が率いる遊撃隊が侵食コアを破壊する。","ENG":"While we fight with Elysium, my sister will lead her guerilla force to destroy it.","TWN":"當我們對付樂團時，我的妹妹會帶領一支遊擊隊去摧毀侵蝕核心。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SID_CARDENAS_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SID_CARDENAS_NPC_NULL","text":{"KOREA":" 침식 코어가 파괴되면, 이면세계가 붕괴하겠지.","JPN":" 侵食コアを破壊すれば、裏世界は崩壊するだろう。","ENG":"Once the Corruption Core is destroyed, the Counterside will collapse.","TWN":"侵蝕核心被破壞後，異界自然就會崩潰。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SID_CARDENAS_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SID_CARDENAS_NPC_NULL","text":{"KOREA":" 그 붕괴에 휘말리면, 제아무리 데모고르곤이라고 해도 무사하지 못해.","JPN":" その崩壊に巻き込まれれば、いくらデモゴルゴンだとしても無事ではいられまい。","ENG":"Anyone caught in the collapse won't make it out alive, not even a Demogorgon.","TWN":"如果被捲入這次崩潰，就算是魔神也無法平安無事。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SID_CARDENAS_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SID_CARDENAS_NPC_NULL","text":{"KOREA":" 휘말리지 않아도, 엘리시움 필하모닉에게 막대한 피해를 줄 수 있다면 그걸로 충분하고.","JPN":" 巻き込まれなくても、エリシウムフィルハーモニーに莫大な被害を与えられるならそれで十分だ。","ENG":"Even if she doesn't get caught in it, just causing massive damage to Elysium Philharmonic will also be enough.","TWN":"即使沒能給她造成傷害，只要能夠傷及愛樂組織本身，那就足夠了。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SID_CARDENAS_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SID_CARDENAS_NPC_NULL","text":{"KOREA":" 적어도 클리포트 게임 중에 관리국을 방해하지 않을 정도면 돼.","JPN":" 少なくとも、クリフォトゲームの途中で管理局の邪魔をされるのは防ぎたい。","ENG":"At the very least, it'll be enough to keep them from disrupting the Administration during the Qliphoth Game.","TWN":"至少在逆卡巴拉遊戲的時候，讓他們無法妨礙管理局就足夠了。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SID_CARDENAS_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" …….","JPN":" ……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SID_CARDENAS_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SID_CARDENAS_NPC_NULL","text":{"KOREA":" 이미 지휘부에 작전 제안서는 올려둔 상태야.","JPN":" すでに司令部に作戦提案書を提出した状態だ。","ENG":"I've already submitted the operation proposal to the Headquarters.","TWN":"作戰方案我已提交至指揮中心。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SID_CARDENAS_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SID_CARDENAS_NPC_NULL","text":{"KOREA":" 승인된다면, 하이브 컨트롤의 연산으로 최적의 타이밍을 계산해주겠지.","JPN":" 承認されれば、ハイブコントロールの演算により最適なタイミングを算出してくれるだろう。","ENG":"Once approved, Hive Control will calculate the optimal timing.","TWN":"獲得批准後，巢穴控制系統將計算最佳時間。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SID_CARDENAS_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SID_CARDENAS_NPC_NULL","text":{"KOREA":" 세부 사항을 열람할 수 있도록 자네에게도 공유해주겠네.","JPN":" 詳細を閲覧できるように、君とも共有しよう。","ENG":"I'll grant you access as well so you can read the details.","TWN":"詳細的資訊我會與你分享。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SID_CARDENAS_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" ……알겠습니다. 카르데나스 전대장님.","JPN":" ……わかりました。カルデナス戦隊長。","ENG":"...Understood, Cardenas Commander.","TWN":"……我知道了。卡特納斯戰隊長。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SID_CARDENAS_NPC_NULL","text":{"KOREA":" 명심하게. 야크샤 부전대장.","JPN":" 忘れるな。ヤクシャー副戦隊長。","ENG":"Remember, Yaksha Deputy Commander.","TWN":"記住。夜叉副戰隊長。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SID_CARDENAS_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SID_CARDENAS_NPC_NULL","text":{"KOREA":" 문제가 일어날 걸 알고 있으면서도, 그걸 방치해두는 건 어리석은 일이야.","JPN":" 問題が発生するとわかっていながら、それを放置するのは愚かなことだ。","ENG":"It's foolish to neglect a problem when you know it'll cause trouble.","TWN":"明知會出問題，卻放任不管，是件很愚蠢的事情。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SID_CARDENAS_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SID_CARDENAS_NPC_NULL","text":{"KOREA":" 다가 올 클리포트 게임의 성공을 위해서라도, 엘리시움 필하모닉은 반드시 배제되어야만 해.","JPN":" 迫るクリフォトゲームの成功に向け、エリシウムフィルハーモニーは必ず排除する必要がある。","ENG":"For the success of the upcoming Qliphoth Game, Elysium Philharmonic must be eradicated.","TWN":"為了即將到來的逆卡巴拉遊戲的成功，愛樂組織必須被排除在外。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SID_CARDENAS_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" …….","JPN":" ……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" 옳은 말이야.","JPN":" 正しいことよ。","ENG":"He's right.","TWN":"你說得對。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" 앨리스가 그림자에 삼켜지지 않는 가장 확실한 방법은.","JPN":" アリスがシャドウに飲まれない一番確実な方法は......","ENG":"The surest way to prevent Alice from being swallowed by the Shadow is...","TWN":"防止艾莉絲被暗影吞噬最穩妥的方法。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" 카르멘을 죽이고, 그 악기를 완전히 소멸시켜버리는 방법 밖에 없어.","JPN":" カルメンを殺して、その楽器を滅させるしかないの。","ENG":"to kill Carmen and completely destroy the instrument.","TWN":"就是殺死卡門，徹底毀掉她的樂器。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" 그걸 위해서라면, 나는 얼마든지…….","JPN":" そのためなら、私はいくらでも……","ENG":"For that, I'd do anything...","TWN":"為此，我樂意做任何事……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" …….","JPN":" ……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" 작전명, <color=#ffd34c>트러블 슈팅</color>이라…….","JPN":" 作戦名、<color=#ffd34c>トラブルシューティング</color>、ね……","ENG":"Operation <color=#ffd34c>Troubleshooting</color>…","TWN":"作戰代號，<color=#ffd34c>故障排除</color>嗎……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"subtitle","speaker":null,"text":{"KOREA":" 얼마 뒤","JPN":" しばらくして","ENG":"A few days later","TWN":"不久後"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"subtitle","speaker":null,"text":{"KOREA":" 관리국 제4 수색전대 <color=#ffd34c>야크샤</color> 본부\\n작전 당일","JPN":" 管理局第4捜索戦隊<color=#ffd34c>ヤクシャー</color>本部\\n作戦当日","ENG":"Administration 4th Recon Division <color=#ffd34c>Yaksha</color> HQ\\nOperation D-day","TWN":"管理局第4偵察戰隊<color=#ffd34c>夜叉</color>總部\\n作戰當天"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":" ……정말 괜찮겠어, 부전대장?","JPN":" ……本当にいいのか、副戦隊長？","ENG":"...Are you sure you'll be all right, Deputy Commander?","TWN":"……副戰隊長，你確定沒問題嗎？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" 후후, 전대장님께서 걱정해주니까, 기분이 꽤 나쁘지 않은걸?","JPN":" ふふ、戦隊長が心配してくれるなんて、うれしいわ。","ENG":"Fu fuu. It's not bad having the Commander worry about me.","TWN":"呵呵，有戰隊長擔心我，我很開心喔？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" 하지만 걱정하지 마. 이 작전은 그냥 3년 전 작전의 사후처리 같은 거니까.","JPN":" でも、大丈夫よ。この作戦は3年前の作戦の事後処理みたいなものだから。","ENG":"But don't worry. This is just a follow-up to the operation from three years ago.","TWN":"但不用擔心。這次作戰只是三年前行動的後續作戰。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":" ……알고 있어.","JPN":" ……わかってる。","ENG":"...I know.","TWN":"……我知道。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":" 작전 보고서라면 나도 읽어 봤으니까.","JPN":" 作戦報告書ならアタシも読んだから。","ENG":"I also read the operation report.","TWN":"作戰報告我也看過。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":" 시드 아저씨랑 피오의 실력을 의심하는 건 아니야. 하지만…….","JPN":" シドのおっさんとピオの実力を疑っているわけじゃない。でも……","ENG":"I'm not doubting Sid and Pio, but...","TWN":"我相信錫德大叔和妃歐實力。但是……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":" 젠장, 그래도 혹시 몰라! 예감이 안 좋다고!","JPN":" くそ、でもわからないだろ！　悪い予感がするんだよ！","ENG":"Agh! But you never know! I got a bad feeling about this!","TWN":"呃！該死！我就是有一種不好的預感！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":" 그 필하모닉 홀이잖아. 무슨 일이 생겨도 이상하지 않아.","JPN":" あのフィルハーモニーホールだろ？ 何かあってもおかしくない。","ENG":"It's Philharmonic Hall. Anything can go wrong down there.","TWN":"那裡是管弦樂廳。發生什麼事情也並不奇怪。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" …….","JPN":" ……","ENG":"...","TWN":"……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":" 아무리 생각해봐도 이건 우리 작전보다 카르데나스의 작전이 우선순위가 높아.","JPN":" どう考えても、アタシたちの作戦よりカルデナスの作戦を優先するべきだ。","ENG":"No matter how I see it, Cardenas's operation has a higher priority than ours.","TWN":"不管我怎麼想，卡特納斯的作戰優先順序都高於我們。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":" 그러니까 지금이라도 작전을 미루고, 야크샤 전원이 카르데나스에 협력하는 게……!","JPN":" だから今でも作戦を後まわしにして、ヤクシャー全員がカルデナスのほうに協力した方が……！","ENG":"So, I think it's best to postpone our operation for Yaksha to help Cardenas–!","TWN":"所以，現在還不如推遲作戰，讓夜叉全員配合卡特納斯……！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" 괜찮아. 앨리스.","JPN":" 大丈夫よ。アリス。","ENG":"It's okay, Alice.","TWN":"沒事的，艾莉絲。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" 혹시 모를 경우를 대비해서 메이즈와 카멜롯이 지휘부에서 대기하고 있어.","JPN":" 万が一に備えて、メイズとキャメロットが司令部で待機してるの。","ENG":"In case anything happens, the Headquarters has put Maze and Camelot on standby.","TWN":"以防萬一，梅茲和卡梅羅會在指揮部待命的。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":" 메이즈 전대장님이?","JPN":" メイズ戦隊長が？","ENG":"Maze Commander?","TWN":"梅茲戰隊長？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" 무엇보다도 전대장의 결정이 그렇게 쉽게 바뀌면 못 써.","JPN":" 戦隊長の決定が簡単に覆るようじゃダメよ。","ENG":"But above all, a Commander shouldn't change decisions so easily.","TWN":"最重要的是，戰隊長的決定不能這麼輕易更改。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" 이제 넌 야크샤의 우두머리야. 이젠 전대원들이 너에게 의지하고 있는 걸.","JPN":" あなたはもうヤクシャーのリーダーなの。戦隊員はあなたを頼りにしてるんだから。","ENG":"You're the head of Yaksha now. Everyone here is relying on you.","TWN":"你現在是夜叉的領袖。戰隊員今後就交給你了。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":" …….","JPN":" ……","ENG":"...","TWN":"……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" 그러니까 내 걱정은 하지 말고 안심하고 다녀오도록 해.","JPN":" だから私の心配なんてしないで、安心していってらっしゃい。","ENG":"So don't worry about me and go do what you must.","TWN":"所以不用擔心我，我會平安回來的。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":" 나도 반드시 내 역할을 성공시키고 말 테니까.","JPN":" 私も私の仕事を絶対に成功させてみせるわ。","ENG":"I'll successfully complete my role too.","TWN":"我一定盡好我的職責。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":" ……알겠어.","JPN":" ……わかった。","ENG":"...Okay.","TWN":"……知道了。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":" 무사히 돌아오라고, 부전대장.","JPN":" 無事に帰って来いよ、副戦隊長。","ENG":"You'd better return safe and sound, Deputy Commander.","TWN":"要給我平安回來啊，副戰隊長。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":" 모든 전대원들은 주목! 현재 이곳은 심도 3의 이면세계다!","JPN":" 全戦隊員、注目！　現在、ここは深度3の裏世界だ！","ENG":"Attention everyone! We are currently in Depth 3 of the Counterside!","TWN":"全體隊員注意！目前區域是深度3的異界！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":" 오늘 우리의 수색 목표는 모더레이터로 위장한 적성 개체이다.","JPN":" 今日のアタシたちの捜索目標は、モデレーターに偽装した敵性個体だ。","ENG":"Today, our objective is to search for a hostile entity disguised as a Moderator.","TWN":"我們今天的偵察目標是偽裝成仲裁者的敵人。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":" 녀석은 주위의 침식파를 흡수하여, 동력원으로 바꾸는 특성을 가지고 있다!","JPN":" やつは周りの侵食波を吸収し、動力源に変える特性を持っている！","ENG":"This thing has the ability to absorb Corruption rays from its surroundings to use as its power source!","TWN":"它有能力吸收周圍的侵蝕波，將其轉化為動力源！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":" 이 세계에서 관측된 모더레이터는 총 3기.","JPN":" この世界で観測されたモデレーターは全部で3機。","ENG":"There are a total of three Moderators observed in this world.","TWN":"這個世界上總共偵測到了3架仲裁者。"},"stage":{"bg":"MAINSTREAM_5201001","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":" 녀석들 중에 주변 CSE 레벨을 낮추는 녀석이 있다면 그 녀석이 빙고야!","JPN":" もしもやつらの中に周りのCSEレベルを下げるやつがいれば、そいつがビンゴだ！","ENG":"If you come across one that has lower CSE Levels surrounding it, it's our target!","TWN":"如果其中有會降低周圍CSE等級的傢伙，那麼它就是我們的目標！"},"stage":{"bg":"MAINSTREAM_5201001","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":" 모든 전대원은 삼인일조로 행동하되, 위험할 것 같으면 날 불러.","JPN":" 全戦隊員は3人1組で行動し、危険を感じたらアタシを呼べ。","ENG":"All units should work in groups of three, but report to me if anything seems dangerous.","TWN":"全體隊員三人一組行動，如果有任何危險，請呼叫我。"},"stage":{"bg":"MAINSTREAM_5201001","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":" 반드시 구해줄 테니까.","JPN":" 必ず助けてやる。","ENG":"I'll come save you.","TWN":"我一定會來救你們的。"},"stage":{"bg":"MAINSTREAM_5201001","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":" 그럼, 야크샤 전대. 수색을 시작한다!","JPN":" では、ヤクシャー戦隊。捜索を開始する！","ENG":"Then, the Yaksha Division. Start searching!","TWN":"那麼，夜叉戰隊。偵察開始！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIMENSIONTRIMMING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};